var e=[{id:`L1_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`……인정할 수 없습니다.`,JPN:`……認められません。`,ENG:`...I beg to differ.`,TWN:`……我不承認。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L2_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`당장 이 미친 짓을 중단하세요. 연구했다는 사실만으로도 관리국이 개입할 수 있습니다.`,JPN:`今すぐこのとんでもないことを中断してください。研究したという事実だけでも管理局が介入する可能性があります。`,ENG:`I command you to stop this insanity this instant. Just the fact that research was conducted would get the Administration involved.`,TWN:`請立即停止瘋狂的行為。僅憑你們插手研究這件事本身，管理局就可以介入。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`BIO_NPC_ESPR2_NULL`,text:{KOREA:`연구를 중단할지 말지는 학회장님과 논의하시오.`,JPN:`研究を中断するかどうかは学会長と議論したまえ。`,ENG:`Please talk with the President about whether we should abort our projects or not.`,TWN:`是否停止研究這件事，你還是跟學會長討論吧。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L4_1`,type:`dialog`,speaker:`BIO_NPC_ESPR2_NULL`,text:{KOREA:`이번 연구는 이미 그분에게 인가를 받았소. 부학회장 권한 밖에 있는 일이외다.`,JPN:`今度の研究はすでにあの方から許可を得ている。副学会長にどうこうできる権限はない。`,ENG:`This research was ordered directly by the President. With all due respect, you have no authority to disband it.`,TWN:`因為這次的研究，已經取得了她的同意。這件事已經超出了副學會長的許可權。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`에델에게 말인가요?`,JPN:`エデルにですか？`,ENG:`Edel ordered this?`,TWN:`你是說艾瑟兒嗎？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`에델은 인간을 벗어난 존재입니다. 지식을 얻을 수 있다면 자신에게 닥칠 위험도 개의치 않아요.`,JPN:`エデルは人間の枠から外れた存在です。知識を得られるのなら自らに迫る危険さえも気に留めませんわ。`,ENG:`Edel is a non-human being. She will do anything, including putting herself in danger, in order to gain knowledge.`,TWN:`艾瑟兒是超出人類的存在。只要能得到知識，她連自己面臨的危險都不在乎。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`사람이면서 그런 그녀의 판단에 아무 의심 없이 따르겠다니, 대체 뭐 때문에……!`,JPN:`人でありながらそんな彼女の判断に何の疑いもなく従うなんて、いったい何のために……！`,ENG:`But you are human. Why then do you not question her motives and follow her instructions? For what, exactly...?!`,TWN:`作為人類，你居然毫無疑義地聽從她的判斷，究竟是為什麼……！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`BIO_NPC_ESPR2_NULL`,text:{KOREA:`우스꽝스러운 질문이군. 그야 더 많은 지식을 위해서지.`,JPN:`愚問だな。もちろんより多くの知識を得るためだ。`,ENG:`A moot question, indeed. That is to gain more knowledge, of course.`,TWN:`這個問題太可笑了。當然是為了得到更多的知識。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_PRIDE`}}}},{id:`L9_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`저는 그 집착에 사로잡힌 희생자들을 똑똑히 봤습니다!`,JPN:`私はその執着に囚われた犠牲者たちを見てきました！`,ENG:`I have seen the victims of obsession with my own eyes!`,TWN:`我清楚地看見了那些被執念束縛的犧牲者！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_PRIDE`}}}},{id:`L10_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`그런 짓들을 계속하게 내버려 둘 수는 없어요!`,JPN:`このまま放っておくわけにはいきません！`,ENG:`I will not allow this to continue any longer!`,TWN:`我不能再繼續放任這些事不管！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`BIO_NPC_ESPR2_NULL`,face:`UNIT_PRIDE`}}}}];export{e as default};